message:
test(fcp-e2e): thread CapabilityConstraints through full_system_e2e's build_token

Applies the same constraints payload pattern already adopted by the
per-connector compliance tests. Inside `build_token`:

    let constraints = fcp_core::CapabilityConstraints {
        resource_allow: vec!["*".to_string()],
        ..Default::default()
    };
    let mut constraints_cbor = Vec::new();
    ciborium::into_writer(&constraints, &mut constraints_cbor)
        .expect("serialize test constraints");
    let cose = CapabilityTokenBuilder::new()
        ...
        .constraints_cbor(&constraints_cbor)
        .sign(signing_key)
        ...

Previously this end-to-end test emitted capability tokens without any
constraints block, which was tolerated by older hosts but is rejected
by the current capability-enforcement path. No assertion changes; the
test still exercises the full host/connector flow end to end.

files.patch:
@@ -194,13 +194,21 @@ fn build_token(
     operations: &[&str],
 ) -> CapabilityToken {
     let now = Utc::now();
+    let constraints = fcp_core::CapabilityConstraints {
+        resource_allow: vec!["*".to_string()],
+        ..Default::default()
+    };
+    let mut constraints_cbor = Vec::new();
+    ciborium::into_writer(&constraints, &mut constraints_cbor)
+        .expect("serialize test constraints");
     let cose = CapabilityTokenBuilder::new()
         .capability_id(capability)
         .zone_id("z:work")
         .principal("user:test")
         .operations(operations)
         .issuer("node:test")
         .validity(now, now + ChronoDuration::hours(1))
+        .constraints_cbor(&constraints_cbor)
         .sign(signing_key)
         .expect("capability token sign");
     CapabilityToken::from_raw(cose)
